actionConfiguration.body:
EXEC dbo.sp_avance_modificar

    @id_avance =
        {{ appsmith.store.idAVModificar }},

    @fecha_avance =
        {{ dpFecha_AV.selectedDate }},

    @id_metodo =
        {{ selMetodo_de_Pago_AV.selectedOptionValue }},

    @referencia =
        {{ inpReferenciaAV.text }},

    @concepto =
        {{ inpConcepto_AV.text }},

    @observacion =
        {{ inpObservacionAV.text }},

    @monto_retencion_dgii =
        {{ Number((inpRetencionDGIIAV.text || "0").replace(/,/g,"")) }},

    @monto_retencion_itbis =
        {{ Number((inpRetencionItbisAV.text || "0").replace(/,/g,"")) }},

    @monto_retencion_garantia =
        {{ Number((inpRetencionGarantiaAV.text || "0").replace(/,/g,"")) }},

    @monto_retencion_tss =
        {{ Number((inpRetencionTSS_AV.text || "0").replace(/,/g,"")) }},

    @id_tipo_retencion_dgii =
        {{ selTipoRetDGII_AV.selectedOptionValue || null }},

    @id_tipo_retencion_itbis =
        {{ selTipoRetITBIS_AV.selectedOptionValue || null }},

    @id_tipo_retencion_garantia =
        {{ selTipoRetGarantiaAV.selectedOptionValue || null }},

    @id_tipo_retencion_tss =
        {{ selTipoRetTSS_AV.selectedOptionValue || null }},

    @otra_moneda =
        {{ selOtraMonedaAV.selectedOptionValue }},

    @id_moneda_otra_moneda =
        {{
            selOtraMonedaAV.selectedOptionValue == 1
                ? selOtraMonedaCodigoAV.selectedOptionValue
                : null
        }},

    @tasa_pago_otra_moneda =
        {{
            selOtraMonedaAV.selectedOptionValue == 1
                ? Number((inpTasaOtraMonedaAV.text || "0").replace(/,/g,""))
                : null
        }},

    @usuario_evento =
        '{{ appsmith.user.email || "Appsmith" }}',

    @equipo =
        'Appsmith';
